import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/ExacerbationForecast.css';

function ExacerbationForecast() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [healthRecords, setHealthRecords] = useState([]);
  const [currentRecordIndex, setCurrentRecordIndex] = useState(0);
  const [forecastResult, setForecastResult] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [userData, setUserData] = useState(null);

  // Fetch health records and user data when component mounts
  useEffect(() => {
    fetchHealthRecords();
    fetchUserData();
  }, []);

  const fetchUserData = async () => {
    try {
      const user_id = localStorage.getItem('user_id');
      if (!user_id) {
        navigate('/');
        return;
      }

      // Fetch user data (age, sex, smoking, allergies)
      const response = await fetch(`http://localhost:5000/api/user-data/${user_id}`);
      const data = await response.json();
      
      if (response.ok) {
        console.log('Fetched user data:', data);
        setUserData(data);
      } else {
        throw new Error(data.error);
      }
    } catch (error) {
      console.error('Error fetching user data:', error);
      setError('Failed to load user profile data');
    }
  };

  const fetchHealthRecords = async () => {
    setIsLoading(true);
    setError('');

    try {
      const user_id = localStorage.getItem('user_id');
      if (!user_id) {
        navigate('/');
        return;
      }

      const response = await fetch(`http://localhost:5000/api/health-records/${user_id}`);
      if (!response.ok) {
        throw new Error('Failed to fetch records');
      }

      const data = await response.json();
      console.log('Fetched health records:', data);
      
      // Sort by date descending to get latest records first
      const sortedData = data.sort((a, b) => 
        new Date(b.date) - new Date(a.date)
      );
      
      setHealthRecords(sortedData);
      setCurrentRecordIndex(0);
    } catch (error) {
      console.error('Error fetching health records:', error);
      setError('Failed to load health records');
    } finally {
      setIsLoading(false);
    }
  };

  // Process user data for the neural network
  const prepareUserData = () => {
    if (!userData || !healthRecords.length) {
      console.error('Missing user data or health records');
      return null;
    }
    
    try {
      // Get the current health record
      const currentRecord = healthRecords[currentRecordIndex];
      console.log('Current health record:', currentRecord);
      
      // Check if we have all required fields
      if (!currentRecord) {
        console.error('Current record is null or undefined');
        return null;
      }
      
      // Process gender: 0 for male, 1 for female
      const genderValue = userData.sex === 'male' ? 0 : 1;
      console.log('Gender value:', userData.sex, '->', genderValue);
      
      // Process smoking: already stored as 0 or 1
      const smokingValue = parseInt(userData.smoking);
      console.log('Smoking value:', userData.smoking, '->', smokingValue);
      
      // Process allergies: split by comma and convert to binary values
      const allergiesArr = userData.allergy ? userData.allergy.split(',').map(item => item.trim().toLowerCase()) : [];
      console.log('Allergies array:', userData.allergy, '->', allergiesArr);
      
      // Common allergies to check for
      const commonAllergies = ['pollen', 'dust', 'mold', 'pets', 'food'];
      const allergyValues = commonAllergies.map(allergy => {
        const hasAllergy = allergiesArr.some(item => item.includes(allergy)) ? 1 : 0;
        console.log(`Allergy check for ${allergy}:`, hasAllergy);
        return hasAllergy;
      });
      
      // Process medicine: determine medicine type and convert to binary
      const medicineValue = processMedicineData(currentRecord.medicine);
      console.log('Medicine values:', currentRecord.medicine, '->', medicineValue);
      
      // Log raw values before parsing
      console.log('Raw health values:', {
        age: userData.age,
        FEV1: currentRecord.FEV1,
        FVC: currentRecord.FVC,
        PEF: currentRecord.PEF,
        respiratory_rate: currentRecord.respiratory_rate,
        pulse: currentRecord.pulse,
        cough: currentRecord.cough,
        breathlessness: currentRecord.breathlessness,
        wheezing: currentRecord.wheezing,
        chest_tightness: currentRecord.chest_tightness,
        nighttime_awakenings: currentRecord.nighttime_awakenings
      });
      
      // Ensure all values are properly parsed as numbers
      const features = [
        parseInt(userData.age) || 0,
        genderValue,
        smokingValue,
        ...allergyValues,
        parseFloat(currentRecord.FEV1) || 0,
        parseFloat(currentRecord.FVC) || 0,
        parseInt(currentRecord.PEF) || 0,
        parseInt(currentRecord.respiratory_rate) || 0,
        parseInt(currentRecord.pulse) || 0,
        parseInt(currentRecord.cough) || 0,
        parseInt(currentRecord.breathlessness) || 0,
        parseInt(currentRecord.wheezing) || 0,
        parseInt(currentRecord.chest_tightness) || 0,
        parseInt(currentRecord.nighttime_awakenings) || 0,
        ...medicineValue
      ];
      
      // Log the features for debugging
      console.log('Prepared features for prediction:', features);
      console.log('Features array length:', features.length);
      
      // Create a more readable version of features
      const featureLabels = [
        'age', 'gender', 'smoking', 
        'allergy_pollen', 'allergy_dust', 'allergy_mold', 'allergy_pets', 'allergy_food',
        'FEV1', 'FVC', 'PEF', 'respiratory_rate', 'pulse',
        'cough', 'breathlessness', 'wheezing', 'chest_tightness', 'nighttime_awakenings',
        'medicine_inhaler', 'medicine_steroid', 'medicine_bronchodilator', 
        'medicine_antibiotic', 'medicine_antihistamine'
      ];
      
      const namedFeatures = {};
      featureLabels.forEach((label, index) => {
        namedFeatures[label] = features[index];
      });
      
      console.log('Named features:', namedFeatures);
      
      return features;
    } catch (error) {
      console.error('Error preparing user data:', error);
      setError('Error processing health data: ' + error.message);
      return null;
    }
  };
  
  // Process medicine information
  const processMedicineData = (medicineText) => {
    // Initialize medicine categories with 0 (not using)
    const medicineCategories = {
      'inhaler': 0,
      'steroid': 0,
      'bronchodilator': 0,
      'antibiotic': 0,
      'antihistamine': 0
    };
    
    if (!medicineText || medicineText === 'None') {
      console.log('No medicine data found');
      return Object.values(medicineCategories);
    }
    
    const medicineLower = medicineText.toLowerCase();
    console.log('Processing medicine text:', medicineLower);
    
    // Check for different medicine types
    if (medicineLower.includes('inhaler') || medicineLower.includes('ventolin') || medicineLower.includes('albuterol')) {
      medicineCategories.inhaler = 1;
      console.log('Detected inhaler');
    }
    
    if (medicineLower.includes('steroid') || medicineLower.includes('cortico') || medicineLower.includes('fluticasone')) {
      medicineCategories.steroid = 1;
      console.log('Detected steroid');
    }
    
    if (medicineLower.includes('broncho') || medicineLower.includes('salbutamol') || medicineLower.includes('formoterol')) {
      medicineCategories.bronchodilator = 1;
      console.log('Detected bronchodilator');
    }
    
    if (medicineLower.includes('anti') && medicineLower.includes('biotic')) {
      medicineCategories.antibiotic = 1;
      console.log('Detected antibiotic');
    }
    
    if (medicineLower.includes('antihistamine') || medicineLower.includes('fexofenadine') || medicineLower.includes('cetirizine')) {
      medicineCategories.antihistamine = 1;
      console.log('Detected antihistamine');
    }
    
    console.log('Processed medicine categories:', medicineCategories);
    return Object.values(medicineCategories);
  };

  // Simple neural network prediction (simulated)
  const neuralNetworkPredict = (features) => {
    try {
      console.log('NEURAL NETWORK PREDICTION STARTED');
      
      // Check if features are valid
      if (!features || features.length < 20) {
        console.error('Invalid features array provided to prediction function', features);
        throw new Error('Invalid input data for prediction');
      }
      
      console.log('Input features:', features);
      
      // BUGFIX: Complete rebuild of prediction algorithm
      
      // Set base score depending on symptoms (index 13-17)
      // These have the most direct impact on exacerbation risk
      let symptomsScore = 0;
      
      // Cough (0-5 scale)
      const coughLevel = features[13] || 0;
      symptomsScore += coughLevel * 0.8;
      console.log('Cough contribution:', coughLevel * 0.8);
      
      // Breathlessness (0-5 scale)
      const breathlessnessLevel = features[14] || 0;
      symptomsScore += breathlessnessLevel * 1.0;
      console.log('Breathlessness contribution:', breathlessnessLevel * 1.0);
      
      // Wheezing (0-5 scale)
      const wheezingLevel = features[15] || 0;
      symptomsScore += wheezingLevel * 0.9;
      console.log('Wheezing contribution:', wheezingLevel * 0.9);
      
      // Chest tightness (0-5 scale)
      const chestTightnessLevel = features[16] || 0;
      symptomsScore += chestTightnessLevel * 0.7;
      console.log('Chest tightness contribution:', chestTightnessLevel * 0.7);
      
      // Nighttime awakenings (0-5 scale)
      const nighttimeAwakeningsLevel = features[17] || 0;
      symptomsScore += nighttimeAwakeningsLevel * 0.8;
      console.log('Nighttime awakenings contribution:', nighttimeAwakeningsLevel * 0.8);
      
      console.log('Total symptoms score:', symptomsScore);
      
      // Lung function contribution
      let lungFunctionScore = 0;
      
      // FEV1 (higher is better, so negative contribution to risk)
      const fev1 = features[8] || 0;
      const fev1Contribution = fev1 < 2 ? 2 : fev1 < 3 ? 1 : fev1 < 4 ? 0 : -1;
      lungFunctionScore += fev1Contribution;
      console.log('FEV1 contribution:', fev1Contribution);
      
      // FVC (higher is better, so negative contribution to risk)
      const fvc = features[9] || 0;
      const fvcContribution = fvc < 2 ? 1 : fvc < 3 ? 0.5 : fvc < 4 ? 0 : -0.5;
      lungFunctionScore += fvcContribution;
      console.log('FVC contribution:', fvcContribution);
      
      // PEF (higher is better, so negative contribution to risk)
      const pef = features[10] || 0;
      const pefContribution = pef < 250 ? 2 : pef < 350 ? 1 : pef < 450 ? 0 : -1;
      lungFunctionScore += pefContribution;
      console.log('PEF contribution:', pefContribution);
      
      console.log('Total lung function score:', lungFunctionScore);
      
      // Vital signs contribution
      let vitalSignsScore = 0;
      
      // Respiratory rate (normal range 12-20)
      const respiratoryRate = features[11] || 0;
      const respiratoryRateContribution = respiratoryRate > 25 ? 2 : respiratoryRate > 20 ? 1 : 0;
      vitalSignsScore += respiratoryRateContribution;
      console.log('Respiratory rate contribution:', respiratoryRateContribution);
      
      // Pulse (normal range 60-100)
      const pulse = features[12] || 0;
      const pulseContribution = pulse > 110 ? 1.5 : pulse > 100 ? 1 : pulse > 90 ? 0.5 : 0;
      vitalSignsScore += pulseContribution;
      console.log('Pulse contribution:', pulseContribution);
      
      console.log('Total vital signs score:', vitalSignsScore);
      
      // Risk factors contribution
      let riskFactorsScore = 0;
      
      // Age (higher age increases risk)
      const age = features[0] || 0;
      const ageContribution = age > 65 ? 1.5 : age > 50 ? 1 : age > 40 ? 0.5 : age < 12 ? 0.5 : 0;
      riskFactorsScore += ageContribution;
      console.log('Age contribution:', ageContribution);
      
      // Smoking (binary 0-1)
      const smoking = features[2] || 0;
      const smokingContribution = smoking * 2; // Significant risk factor
      riskFactorsScore += smokingContribution;
      console.log('Smoking contribution:', smokingContribution);
      
      // Allergies (indices 3-7, binary 0-1 each)
      let allergiesContribution = 0;
      for (let i = 0; i < 5; i++) {
        allergiesContribution += (features[3 + i] || 0) * 0.3;
      }
      riskFactorsScore += allergiesContribution;
      console.log('Allergies contribution:', allergiesContribution);
      
      console.log('Total risk factors score:', riskFactorsScore);
      
      // Medication effect (negative contribution - reduces risk)
      let medicationEffect = 0;
      
      // Inhaler
      const inhaler = features[18] || 0;
      medicationEffect -= inhaler * 0.5;
      
      // Steroid
      const steroid = features[19] || 0;
      medicationEffect -= steroid * 1.5;
      
      // Bronchodilator
      const bronchodilator = features[20] || 0;
      medicationEffect -= bronchodilator * 1.0;
      
      // Other medications
      medicationEffect -= (features[21] || 0) * 0.5; // Antibiotic
      medicationEffect -= (features[22] || 0) * 0.3; // Antihistamine
      
      console.log('Total medication effect:', medicationEffect);
      
      // Calculate overall risk score
      // Weight the components differently based on their importance
      const weightedSymptoms = symptomsScore * 1.5;
      const weightedLungFunction = lungFunctionScore * 1.2;
      const weightedVitalSigns = vitalSignsScore * 0.8;
      const weightedRiskFactors = riskFactorsScore * 0.7;
      const weightedMedication = medicationEffect; // Already weighted
      
      console.log('Weighted components:',
        { weightedSymptoms, weightedLungFunction, weightedVitalSigns, weightedRiskFactors, weightedMedication }
      );
      
      // Sum all weighted components
      const baseScore = weightedSymptoms + weightedLungFunction + weightedVitalSigns + 
                      weightedRiskFactors + weightedMedication;
      
      console.log('Base score before scaling:', baseScore);
      
      // Use a logistic function to convert score to probability
      // First normalize the score to a reasonable range
      const normalizedScore = baseScore / 10; // Adjust divisor based on expected range
      
      console.log('Normalized score:', normalizedScore);
      
      // Apply logistic function to get probability
      const logistic = x => 1 / (1 + Math.exp(-x));
      const rawProbability = logistic(normalizedScore) * 100;
      
      console.log('Raw probability from logistic function:', rawProbability);
      
      // Adjust to ensure values are within range 5-95%
      const finalProbability = Math.min(Math.max(rawProbability, 5), 95);
      
      console.log('Final adjusted probability:', finalProbability);
      
      // Display which factors contributed most to the risk
      const factors = [
        { name: 'Symptoms', value: weightedSymptoms },
        { name: 'Lung Function', value: weightedLungFunction },
        { name: 'Vital Signs', value: weightedVitalSigns },
        { name: 'Risk Factors (Age, Smoking, Allergies)', value: weightedRiskFactors },
        { name: 'Medication Effect', value: weightedMedication }
      ];
      
      const sortedFactors = factors.sort((a, b) => Math.abs(b.value) - Math.abs(a.value));
      console.log('Factors contributing to risk (sorted by importance):', sortedFactors);
      
      return Math.round(finalProbability);
    } catch (error) {
      console.error('Error in neural network prediction:', error);
      throw new Error('Failed to calculate prediction: ' + error.message);
    }
  };

  const handleForecast = () => {
    if (healthRecords.length === 0 || !userData) {
      setError('Cannot forecast: Missing health records or user profile data');
      setForecastResult(null);
      return;
    }
    
    setIsLoading(true);
    setError('');
    setForecastResult(null); // Clear previous result
    
    console.log('=== STARTING NEW FORECAST ===');
    console.log('Current record index:', currentRecordIndex);
    console.log('Current health record:', healthRecords[currentRecordIndex]);
    console.log('User data:', userData);
    
    try {
      // Process user data
      const features = prepareUserData();
      
      if (!features) {
        setIsLoading(false);
        setError('Failed to process health data for forecasting');
        return;
      }
      
      // Simulate processing time
      setTimeout(() => {
        try {
          // Get prediction from "neural network"
          const probability = Math.round(neuralNetworkPredict(features));
          
          // Determine risk level
          const riskLevel = probability < 30 ? 'low' : probability <= 70 ? 'moderate' : 'high';
          console.log('Risk level determined:', riskLevel, 'with probability', probability);
          
          // Generate recommendations based on risk level and health data
          const recommendations = generateRecommendations(riskLevel, healthRecords[currentRecordIndex]);
          
          // Create forecast result with recommendations
          const result = {
            probability,
            riskLevel,
            recommendations
          };
          
          console.log('Final forecast result:', result);
          setForecastResult(result);
          setIsLoading(false);
        } catch (error) {
          console.error('Error in forecast calculation:', error);
          setError('Failed to calculate forecast: ' + error.message);
          setIsLoading(false);
        }
      }, 500); // Reduced time for quicker debugging
    } catch (error) {
      console.error('Error in forecast handling:', error);
      setError('Error preparing forecast: ' + error.message);
      setIsLoading(false);
    }
  };

  // Generate personalized recommendations based on risk level and health data
  const generateRecommendations = (riskLevel, healthRecord) => {
    const recommendations = [];
    
    // Get personalized recommendations based on user data and risk level
    if (riskLevel === 'low') {
      recommendations.push('Continue your current treatment plan');
      recommendations.push('Monitor your symptoms regularly');
      
      // Add specific recommendations based on actual data
      if (healthRecord.cough > 0) {
        recommendations.push('Track your cough symptoms to ensure they don\'t worsen');
      }
      
      if (parseFloat(healthRecord.FEV1) < 3) {
        recommendations.push('Your lung function is good, but continue regular measurements');
      }
      
      if (parseInt(healthRecord.pulse) > 90) {
        recommendations.push('Your heart rate is slightly elevated - consider consulting with your physician');
      }
    } 
    else if (riskLevel === 'moderate') {
      recommendations.push('Be vigilant about your symptoms');
      recommendations.push('Ensure your rescue inhaler is always accessible');
      
      // Add specific recommendations based on actual data
      if (parseInt(healthRecord.cough) >= 2) {
        recommendations.push('Pay attention to your increased cough - contact your doctor if it worsens');
      }
      
      if (parseInt(healthRecord.nighttime_awakenings) > 0) {
        recommendations.push('Nighttime symptoms may indicate your asthma needs better control');
      }
      
      if (parseInt(healthRecord.breathlessness) > 0 || parseInt(healthRecord.wheezing) > 0) {
        recommendations.push('Your breathing symptoms suggest your treatment plan may need adjustment');
      }
      
      if (parseFloat(healthRecord.FEV1) < 2.5 || parseInt(healthRecord.PEF) < 350) {
        recommendations.push('Your lung function is below expected levels - consider consulting your doctor');
      }
    } 
    else { // high risk
      recommendations.push('Contact your healthcare provider as soon as possible');
      recommendations.push('Review and follow your asthma action plan for yellow/red zone');
      recommendations.push('Avoid asthma triggers and reduce physical exertion');
      
      // Add specific recommendations based on actual data
      if (parseFloat(healthRecord.FEV1) < 2 || parseInt(healthRecord.PEF) < 300) {
        recommendations.push('Your lung function values indicate significant restriction - medical attention is advised');
      }
      
      if (parseInt(healthRecord.cough) >= 3 || parseInt(healthRecord.breathlessness) >= 2) {
        recommendations.push('Your symptoms suggest an active exacerbation may be developing');
      }
      
      if (parseInt(healthRecord.nighttime_awakenings) >= 2) {
        recommendations.push('Frequent nighttime awakenings indicate poor asthma control');
      }
      
      if (parseInt(healthRecord.respiratory_rate) > 20 || parseInt(healthRecord.pulse) > 100) {
        recommendations.push('Your vital signs indicate increased stress - urgent medical consultation is recommended');
      }
    }
    
    // If using medication, add specific advice
    if (healthRecord.medicine && healthRecord.medicine !== 'None') {
      recommendations.push('Continue using your prescribed medications as directed');
    } else if (riskLevel !== 'low') {
      recommendations.push('You may need to discuss medication options with your healthcare provider');
    }
    
    return recommendations;
  };

  const handleNextRecord = () => {
    if (currentRecordIndex < healthRecords.length - 1) {
      setCurrentRecordIndex(currentRecordIndex + 1);
      setForecastResult(null);
    }
  };

  const handlePreviousRecord = () => {
    if (currentRecordIndex > 0) {
      setCurrentRecordIndex(currentRecordIndex - 1);
      setForecastResult(null);
    }
  };

  const formatDate = (dateString) => {
    if (!dateString) return '';
    const date = new Date(dateString);
    if (isNaN(date.getTime())) return '';
    return date.toLocaleDateString();
  };

  const getRiskCardClass = (riskLevel) => {
    switch (riskLevel) {
      case 'low':
        return 'risk-card low-risk';
      case 'moderate':
        return 'risk-card moderate-risk';
      case 'high':
        return 'risk-card high-risk';
      default:
        return 'risk-card';
    }
  };

  const getRiskDescription = (riskLevel) => {
    switch (riskLevel) {
      case 'low':
        return 'Low risk of exacerbation. Continue following your treatment plan and regularly monitor your condition.';
      case 'moderate':
        return 'Moderate risk of exacerbation. Pay attention to your symptoms and be prepared to adjust your treatment if necessary.';
      case 'high':
        return 'High risk of exacerbation. It is recommended to consult your doctor immediately and review your treatment plan.';
      default:
        return '';
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  const riskCards = {
    low: {
      title: "Asthma Exacerbation Risk: Low",
      description: "Based on your current indicators, your risk of asthma exacerbation is low.",
      recommendations: [
        "Continue your regular medication as prescribed",
        "Maintain your current activity levels",
        "Keep monitoring your symptoms daily",
        "Ensure your environment is free of known triggers"
      ]
    },
    moderate: {
      title: "Asthma Exacerbation Risk: Moderate",
      description: "Your indicators suggest a moderate risk of asthma exacerbation in the near future.",
      recommendations: [
        "Use your reliever medication if you notice any symptoms",
        "Consider reducing intense physical activities",
        "Monitor your peak flow measurements more frequently",
        "Avoid known triggers and allergens",
        "Stay well-hydrated and get adequate rest"
      ]
    },
    high: {
      title: "Asthma Exacerbation Risk: High",
      description: "Your health indicators show a high risk of asthma exacerbation. Please take precautionary measures.",
      recommendations: [
        "Use your rescue medication as directed by your healthcare provider",
        "Limit outdoor activities, especially in extreme weather",
        "Keep your rescue inhaler with you at all times",
        "Contact your healthcare provider for guidance",
        "Follow your asthma action plan for the red zone",
        "If symptoms worsen significantly, seek immediate medical attention"
      ]
    }
  };

  // Override the riskCards display method to use the generated recommendations
  useEffect(() => {
    if (forecastResult) {
      console.log('Displaying forecast result:', forecastResult);
    }
  }, [forecastResult]);

  return (
    <div className={`exacerbation-forecast-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
            <h1>Asthma Monitoring</h1>
        </div>
        <div className="nav-buttons">
          <button onClick={() => navigate('/profile')} className="profile-button">
            Profile
          </button>
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>
      
      <div className="content">
        <h2>Asthma Exacerbation Risk Forecast</h2>
        
        {error && <div className="error-message">{error}</div>}
        
        <div className="record-navigation">
          {healthRecords.length > 0 && (
            <>
              <button 
                onClick={handlePreviousRecord}
                disabled={currentRecordIndex === 0 || isLoading}
                className="nav-button"
              >
                ← Previous Record
              </button>
              <span className="record-info">
                Record {currentRecordIndex + 1} of {healthRecords.length}
              </span>
              <button 
                onClick={handleNextRecord}
                disabled={currentRecordIndex === healthRecords.length - 1 || isLoading}
                className="nav-button"
              >
                Next Record →
              </button>
            </>
          )}
        </div>
        
        {healthRecords.length > 0 ? (
          <div className="record-table-container">
            <table className="health-record-table">
              <thead>
                <tr>
                  <th>Date</th>
                  <th>FEV1</th>
                  <th>FVC</th>
                  <th>PEF</th>
                  <th>Respiratory Rate</th>
                  <th>Pulse</th>
                  <th>Cough</th>
                  <th>Breathlessness</th>
                  <th>Wheezing</th>
                  <th>Chest Tightness</th>
                  <th>Nighttime Awakenings</th>
                  <th>Medicine</th>
                </tr>
              </thead>
              <tbody>
                <tr>
                  <td>{formatDate(healthRecords[currentRecordIndex]?.date)}</td>
                  <td>{healthRecords[currentRecordIndex]?.FEV1}</td>
                  <td>{healthRecords[currentRecordIndex]?.FVC}</td>
                  <td>{healthRecords[currentRecordIndex]?.PEF}</td>
                  <td>{healthRecords[currentRecordIndex]?.respiratory_rate}</td>
                  <td>{healthRecords[currentRecordIndex]?.pulse}</td>
                  <td>{healthRecords[currentRecordIndex]?.cough}</td>
                  <td>{healthRecords[currentRecordIndex]?.breathlessness}</td>
                  <td>{healthRecords[currentRecordIndex]?.wheezing}</td>
                  <td>{healthRecords[currentRecordIndex]?.chest_tightness}</td>
                  <td>{healthRecords[currentRecordIndex]?.nighttime_awakenings}</td>
                  <td>{healthRecords[currentRecordIndex]?.medicine}</td>
                </tr>
              </tbody>
            </table>
            
            <div className="forecast-controls">
              <button 
                onClick={handleForecast} 
                className="forecast-button"
                disabled={isLoading}
              >
                {isLoading ? 'Calculating...' : 'Run Forecast'}
              </button>
            </div>
            
            {forecastResult && (
              <div className="forecast-result">
                <div className={getRiskCardClass(forecastResult.riskLevel)}>
                  <h3 className="risk-title">
                    {forecastResult.riskLevel === 'low' && 'Low Risk of Asthma Exacerbation'}
                    {forecastResult.riskLevel === 'moderate' && 'Moderate Risk of Asthma Exacerbation'}
                    {forecastResult.riskLevel === 'high' && 'High Risk of Asthma Exacerbation'}
                  </h3>
                  <div className="risk-probability">
                    Exacerbation Probability: <strong>{forecastResult.probability}%</strong>
                  </div>
                  <p className="risk-description">
                    Based on your health data and profile information, we've analyzed your risk of an asthma exacerbation.
                  </p>
                  <div className="recommendations">
                    <h4>Recommendations:</h4>
                    <ul>
                      {forecastResult.recommendations.map((recommendation, index) => (
                        <li key={index}>{recommendation}</li>
                      ))}
                    </ul>
                  </div>
                </div>
              </div>
            )}
            
            <div className="forecast-actions">
              <div className="navigation-links">
                <a href="#" onClick={(e) => { e.preventDefault(); navigate('/recording-indicators'); }}>
                  Return to data entry
                </a>
                <a href="#" onClick={(e) => { e.preventDefault(); navigate('/graphs-of-changes'); }}>
                  View performance graphs
                </a>
              </div>
            </div>
          </div>
        ) : (
          <div className="no-records-message">
            <p>No health records available for forecasting.</p>
            <p>
              <a href="#" onClick={(e) => { e.preventDefault(); navigate('/recording-indicators'); }}>
                Go to data entry
              </a>
            </p>
          </div>
        )}
      </div>

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
         <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/dashboard')}>
            Home
          </button>
          <button onClick={() => navigate('/recording-indicators')}>
            Recording Indicators
          </button>
          <button onClick={() => navigate('/exacerbation-forecast')}>
            Exacerbation Forecast
          </button>
          <button onClick={() => navigate('/graphs-of-changes')}>
            Graphs of Changes
          </button>
          <button onClick={() => navigate('/medication-diary')}>
            Medication Diary
          </button>
        </nav>
      </div>
      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>
    </div>
  );
}

export default ExacerbationForecast;
